+    assert_ne!(unsafe { isblank(b'\t' as c_int) }, 0);
+    assert_eq!(unsafe { isblank(b'\n' as c_int) }, 0);
+    assert_eq!(unsafe { isblank(b'a' as c_int) }, 0);
