+    assert_ne!(unsafe { iscntrl(0x1F) }, 0); // US
+    assert_ne!(unsafe { iscntrl(0x7F) }, 0); // DEL
+    assert_eq!(unsafe { iscntrl(b'A' as c_int) }, 0);
