+    assert_eq!(unsafe { toupper(b'z' as c_int) }, b'Z' as c_int);
+    assert_eq!(unsafe { toupper(b'A' as c_int) }, b'A' as c_int); // already upper
+    assert_eq!(unsafe { toupper(b'0' as c_int) }, b'0' as c_int); // non-alpha unchanged
