+/// Integer comparison function for tree operations.
+unsafe extern "C" fn int_compare(a: *const c_void, b: *const c_void) -> c_int {
+    let va = a as usize as i64;
+    let vb = b as usize as i64;
+    if va < vb {
+        -1
+    } else if va > vb {
+        1
+    } else {
+        0
+    }
+}
